.darma-loader-darma-research-aurora-card-skeleton { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #22c55e); --accent-2: var(--loader-secondary-color, #38bdf8); width: calc(var(--loader-size, 72px) * 2.55); min-width: 160px; padding: 14px; border-radius: 22px; background: linear-gradient(145deg, #121827, #0b1020); box-shadow: inset 0 1px #fff2, 0 18px 40px #02061766; overflow: hidden; position: relative; }
.darma-loader-darma-research-aurora-card-skeleton::before { content: ""; position: absolute; inset: -45%; background: conic-gradient(from 0deg, transparent, var(--accent), var(--accent-2), transparent 45%); animation: darma-loader-darma-research-aurora-card-skeleton-aurora-sweep calc(var(--speed) * 4) linear infinite; opacity: .35; }
.darma-loader-darma-research-aurora-card-skeleton__media, .darma-loader-darma-research-aurora-card-skeleton__row { position: relative; overflow: hidden; background: #293145; border-radius: 14px; z-index: 1; }
.darma-loader-darma-research-aurora-card-skeleton__media { height: calc(var(--loader-size, 72px) * .82); margin-bottom: 14px; }
.darma-loader-darma-research-aurora-card-skeleton__row { height: 11px; margin-top: 10px; width: 100%; }
.darma-loader-darma-research-aurora-card-skeleton__row-lg { width: 82%; }
.darma-loader-darma-research-aurora-card-skeleton__row-sm { width: 55%; }
.darma-loader-darma-research-aurora-card-skeleton__media::after, .darma-loader-darma-research-aurora-card-skeleton__row::after { content: ""; position: absolute; inset: 0; translate: -120% 0; background: linear-gradient(90deg, transparent, #ffffff40, transparent); animation: darma-loader-darma-research-aurora-card-skeleton-aurora-line calc(var(--speed) * 1.45) ease-in-out infinite; }
.darma-loader-darma-research-aurora-card-skeleton__row:nth-of-type(3)::after { animation-delay: .15s; }
.darma-loader-darma-research-aurora-card-skeleton__row:nth-of-type(4)::after { animation-delay: .3s; }
@keyframes darma-loader-darma-research-aurora-card-skeleton-aurora-line { to { translate: 120% 0; } }
@keyframes darma-loader-darma-research-aurora-card-skeleton-aurora-sweep { to { rotate: 360deg; } }

.darma-loader-uiverse-dashboard-shimmer {
  display: grid;
  width: 118px;
  gap: 10px;
}
.darma-loader-uiverse-dashboard-shimmer i {
  display: block;
  height: 10px;
  border-radius: 999px;
  background: linear-gradient(90deg, color-mix(in srgb, var(--loader-color, #06b6d4) 12%, transparent), color-mix(in srgb, var(--loader-color, #06b6d4) 34%, transparent), color-mix(in srgb, var(--loader-color, #06b6d4) 12%, transparent));
  background-size: 220% 100%;
  animation: darma-loader-uiverse-dashboard-shimmer-skeletonShimmer 1.1s linear infinite;
}
.darma-loader-uiverse-dashboard-shimmer i:first-child { width: 72px; height: 44px; border-radius: 14px; }
.darma-loader-uiverse-dashboard-shimmer i:nth-child(2) { width: 100%; }
.darma-loader-uiverse-dashboard-shimmer i:nth-child(3) { width: 76%; }
.darma-loader-uiverse-dashboard-shimmer i:nth-child(4) { width: 54%; }
@keyframes darma-loader-uiverse-dashboard-shimmer-skeletonShimmer { to { background-position: -220% 0; } }

.darma-loader-skeleton-avatar {
  display: grid;
  grid-template-columns: 42px 108px;
  gap: 8px 12px;
  align-items: center;
}
.darma-loader-skeleton-avatar b,
.darma-loader-skeleton-avatar i {
  display: block;
  background: linear-gradient(90deg, color-mix(in srgb, var(--loader-color, #6366f1) 12%, transparent), color-mix(in srgb, var(--loader-color, #6366f1) 32%, transparent), color-mix(in srgb, var(--loader-color, #6366f1) 12%, transparent));
  background-size: 220% 100%;
  animation: darma-loader-skeleton-avatar-shimmer 1s linear infinite;
}
.darma-loader-skeleton-avatar b {
  grid-row: span 2;
  width: 42px;
  height: 42px;
  border-radius: 50%;
}
.darma-loader-skeleton-avatar i {
  height: 11px;
  border-radius: 999px;
}
.darma-loader-skeleton-avatar i:last-child { width: 72%; }
@keyframes darma-loader-skeleton-avatar-shimmer { to { background-position: -220% 0; } }

.darma-loader-skeleton-line {
  display: grid;
  gap: 10px;
  width: 138px;
}
.darma-loader-skeleton-line i {
  display: block;
  height: 12px;
  border-radius: 999px;
  background: linear-gradient(90deg, color-mix(in srgb, var(--loader-color, #6366f1) 12%, transparent), color-mix(in srgb, var(--loader-color, #6366f1) 32%, transparent), color-mix(in srgb, var(--loader-color, #6366f1) 12%, transparent));
  background-size: 220% 100%;
  animation: darma-loader-skeleton-line-shimmer 1.1s linear infinite;
}
.darma-loader-skeleton-line i:nth-child(2) { width: 82%; }
.darma-loader-skeleton-line i:nth-child(3) { width: 58%; }
@keyframes darma-loader-skeleton-line-shimmer {
  to { background-position: -220% 0; }
}

.darma-loader-uiverse-card-line-shimmer {
  display: inline-block;
  width: 104px;
  height: 14px;
  border-radius: 999px;
  background: linear-gradient(90deg, color-mix(in srgb, var(--loader-color, #f59e0b) 12%, transparent), color-mix(in srgb, var(--loader-color, #f59e0b) 35%, transparent), color-mix(in srgb, var(--loader-color, #f59e0b) 12%, transparent));
  background-size: 220% 100%;
  animation: darma-loader-uiverse-card-line-shimmer-skeletonShimmer 1.05s linear infinite;
}
@keyframes darma-loader-uiverse-card-line-shimmer-skeletonShimmer { to { background-position: -220% 0; } }

.darma-loader-uiverse-dashboard-skeleton-card {
  width: 224px;
  height: 256px;
  border-radius: 18px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  background: var(--loader-color, #d4d4d4);
}
.darma-loader-uiverse-dashboard-skeleton-card__thumbnail,
.darma-loader-uiverse-dashboard-skeleton-card__rows span {
  background: linear-gradient(90deg, rgba(115,115,115,.22), color-mix(in srgb, var(--loader-secondary-color, #ffffff) 35%, transparent), rgba(115,115,115,.22));
  background-size: 300% 100%;
  animation: darma-loader-uiverse-dashboard-skeleton-card-skeletonSweep 1.2s ease-in-out infinite;
  border-radius: 10px;
}
.darma-loader-uiverse-dashboard-skeleton-card__thumbnail { width: 100%; height: 128px; }
.darma-loader-uiverse-dashboard-skeleton-card__rows { display: flex; flex-direction: column; gap: 10px; }
.darma-loader-uiverse-dashboard-skeleton-card__rows span { height: 14px; width: 100%; }
.darma-loader-uiverse-dashboard-skeleton-card__rows span:nth-child(2) { width: 80%; }
.darma-loader-uiverse-dashboard-skeleton-card__rows span:nth-child(4) { width: 50%; }
@keyframes darma-loader-uiverse-dashboard-skeleton-card-skeletonSweep { to { background-position: -300% 0; } }

.darma-loader-skeleton-card {
  display: grid;
  gap: 10px;
  width: 148px;
  border-radius: 18px;
  padding: 14px;
  background: color-mix(in srgb, var(--loader-color, #6366f1) 8%, transparent);
}
.darma-loader-skeleton-card b,
.darma-loader-skeleton-card i {
  display: block;
  border-radius: 12px;
  background: linear-gradient(90deg, color-mix(in srgb, var(--loader-color, #6366f1) 14%, transparent), color-mix(in srgb, var(--loader-color, #6366f1) 34%, transparent), color-mix(in srgb, var(--loader-color, #6366f1) 14%, transparent));
  background-size: 220% 100%;
  animation: darma-loader-skeleton-card-shimmer 1.15s linear infinite;
}
.darma-loader-skeleton-card b { height: 44px; }
.darma-loader-skeleton-card i { height: 10px; }
.darma-loader-skeleton-card i:last-child { width: 66%; }
@keyframes darma-loader-skeleton-card-shimmer { to { background-position: -220% 0; } }

.darma-loader-darma-custom-644 {color: var(--loader-color, #94a3b8);
  --loader-secondary-color: var(--loader-secondary-color, #cbd5e1);
  --loader-bg: var(--loader-bg, #f8fafc);

  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 10px;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644__avatar,
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644__line {
  background: color-mix(in srgb, var(--loader-color, #94a3b8) 65%, var(--loader-bg, #f8fafc));
  animation: darma-loader-darma-custom-644-skeletonPulse var(--loader-speed, 1.2s) ease-in-out infinite;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644__avatar {
  width: 48px;
  height: 48px;
  border-radius: 999px;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644__lines {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644__line {
  height: 20px;
  border-radius: 999px;
}
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644__line-short { width: 112px; }
.darma-loader-darma-custom-644 .darma-loader-darma-custom-644__line-long { width: 144px; }
@keyframes darma-loader-darma-custom-644-skeletonPulse {
  0%, 100% { opacity: .45; }
  50% { opacity: 1; }
}
